SELECT DISTINCT genetic_entity.stable_id as stableId,
genetic_entity.entity_type as entityType
FROM genetic_entity

    LEFT JOIN generic_entity_properties ON genetic_entity.id = generic_entity_properties.genetic_entity_id



        genetic_entity.stable_id IN
        #{item}


        AND (genetic_entity.stable_id LIKE CONCAT('%',#{keyword},'%') OR generic_entity_properties.value LIKE CONCAT('%',#{keyword},'%'))



    ORDER BY ${sortBy} 

        ${direction}



    LIMIT #{limit}

        OFFSET #{offset}

SELECT generic_entity_properties.name as name, generic_entity_properties.value as value, genetic_entity.stable_id as stableId FROM generic_entity_properties INNER JOIN genetic_entity ON genetic_entity.id = generic_entity_properties.genetic_entity_id WHERE generic_entity_properties.genetic_entity_id IN ( SELECT genetic_entity.id FROM genetic_entity
genetic_entity.stable_id IN #{item}
)
